99377054-4b32-48dc-8540-2bd09c1aa2d0	7bced69e-a861-4530-9660-e0ddb955d72b	34f49b19-fa2a-409e-92e4-464fb55e553c	67	67	Laxman Singh Champia	laxman-singh-champia	Co-Head of Aladdin Product Engineering	\N	post	[{"id": "blk-img", "type": "image", "order": 0, "content": {"alt": "laxman-singh-champia", "src": "/photos/Laxman Singh Champia.jpeg"}}, {"id": "blk-bio", "type": "paragraph", "order": 1, "content": {"text": "<p>Laxman Singh Champia is Co-Head of Product Engineering at Baalvion Industries Private Limited, leading the design and delivery of the company's platform and products and building scalable, reliable systems that power Baalvion's enterprise solutions.</p><h2>Focus areas</h2><ul><li>Platform architecture and engineering</li><li>Product development and delivery</li><li>Scalable, reliable systems</li><li>Engineering excellence and innovation</li></ul><p>Laxman helps ensure Baalvion Industries' technology is robust, modern and built for global scale.</p>"}}]	[]	{"title": "Laxman Singh Champia", "description": "Laxman Singh Champia oversees the development of Baalvion's core technology platform. With extensive experience in software engineering and product management, he ensures our solutions are innovative, reliable, and scalable."}	published	public	2026-06-07 01:15:42.909+00	\N	3	1	{"kind": "leadership", "role": "Co-Head of Product Engineering", "tier": "functional-leadership", "order": 1, "imageId": "laxman-photo", "imageUrl": "/photos/Laxman Singh Champia.jpeg"}	2026-06-07 01:15:42.362+00	2026-06-07 18:34:45.955+00	["34f49b19-fa2a-409e-92e4-464fb55e553c"]
