10594ed9-adc7-4c10-8582-35fbe398bb7d	f963f97f-e03f-4383-bac3-d8849e9a7c71	\N	67	67	Tax-Loss Harvesting Basics	tax-loss-harvesting-basics	Turning investment losses into a tax advantage.	https://picsum.photos/seed/tax-loss-harvesting-basics/1200/675	article	[{"id": "b0", "type": "paragraph", "order": 0, "content": {"text": "Tax-loss harvesting means selling losers to offset taxable gains."}}, {"id": "b1", "type": "heading", "order": 1, "content": {"text": "How it works", "level": 2}}, {"id": "b2", "type": "paragraph", "order": 2, "content": {"text": "Realized losses offset realized gains, reducing your tax bill."}}, {"id": "b3", "type": "heading", "order": 3, "content": {"text": "Watch the wash sale rule", "level": 2}}, {"id": "b4", "type": "paragraph", "order": 4, "content": {"text": "Buying a substantially identical security within 30 days disallows the loss."}}, {"id": "b5", "type": "callout", "order": 5, "content": {"text": "Harvest thoughtfully — do not let the tax tail wag the investment dog.", "variant": "info"}}]	[]	{"title": "Tax-Loss Harvesting Basics", "description": "Turning investment losses into a tax advantage."}	published	public	2026-05-30 15:23:45.995+00	\N	0	1	{}	2026-05-30 15:23:45.989+00	2026-05-30 15:23:45.998+00	[]
