425c0a2c-7598-4e14-bc96-5fc912b55312	282c6733-7438-4dd4-bfda-64036e98255a	1	Understanding High Jewelry Provenance	{"slug": "guide-high-jewelry-provenance", "title": "Understanding High Jewelry Provenance", "status": "published", "tagIds": [], "excerpt": "A masterclass in certification, origin and the long-term value of fine stones.", "seoMetadata": {"title": "Understanding High Jewelry Provenance", "description": "A masterclass in certification, origin and the long-term value of fine stones."}, "customFields": {"date": "2024-03-12", "kind": "buying-guide", "tips": ["Insist on independent certification (GIA, SSEF, Gübelin) for any significant stone.", "Documented origin materially affects value for sapphires, rubies and emeralds.", "Treatments must be disclosed — untreated stones are rarer and more valuable."], "author": "Elena Vance", "category": "Artisanal", "targetKeyword": "high jewelry provenance guide", "investmentOutlook": "Certified, untreated stones with documented origin command durable premiums at auction."}, "contentBlocks": [{"id": "blk-0", "type": "paragraph", "order": 0, "content": {"text": "In high jewelry, the certificate is as important as the stone. Provenance transforms a beautiful object into an investment."}}, {"id": "blk-1", "type": "paragraph", "order": 1, "content": {"text": "The senior curators at Amarisé evaluate every piece against origin, treatment and craftsmanship before it is offered."}}]}	67	State changed to published	2026-06-10 19:08:01.508+00
